import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';
import Navbar from "./components/Navbar";

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [isRegisterMode, setIsRegisterMode] = useState(false);
  const [busqueda, setBusqueda] = useState('');


  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');
  const [nuevoRol, setNuevoRol] = useState('vendedor');

  const [userRole, setUserRole] = useState('');
  const [view, setView] = useState('dashboard');
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);

  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedId, setSelectedId] = useState(null);
  const [nuevoProd, setNuevoProd] = useState({ nombre: '', stock: 0, precio_venta: 0 });

  const cargarDatos = async () => {
    const resStats = await axios.get('http://localhost:5000/api/stats');
    const resProds = await axios.get('http://localhost:5000/api/productos');
    setStats(resStats.data);
    setProductos(resProds.data);
  };


  useEffect(() => {
    if (isLoggedIn) cargarDatos();
  }, [isLoggedIn]);

  const handleLogin = async () => {
    const res = await axios.post('http://localhost:5000/api/login', { usuario, clave: password });
    if (res.data.success) {
      setIsLoggedIn(true);
      setUserRole(res.data.rol);
    }
  };

  const handleRegister = async () => {
    await axios.post('http://localhost:5000/api/register', { usuario, clave: password, rol: nuevoRol });
    alert("Registro exitoso");
    setIsRegisterMode(false);
  };

  const guardarProducto = async () => {
    if (editMode) {
      await axios.put(`http://localhost:5000/api/productos/${selectedId}`, nuevoProd);
    } else {
      await axios.post('http://localhost:5000/api/productos', nuevoProd);
    }
    setShowForm(false);
    setEditMode(false);
    cargarDatos();
  };

  const prepararEdicion = (p) => {
    setSelectedId(p.id);
    setNuevoProd(p);
    setEditMode(true);
    setShowForm(true);
  };

  const eliminar = async (id) => {
    if (window.confirm("¿Borrar producto?")) {
      await axios.delete(`http://localhost:5000/api/productos/${id}`);
      cargarDatos();
    }
  };


  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>{isRegisterMode ? 'Crear Cuenta' : 'Iniciar Sesión'}</h2>
          <input placeholder="Usuario" value={usuario} onChange={e=>setUsuario(e.target.value)} />
          <input type="password" placeholder="Contraseña" value={password} onChange={e=>setPassword(e.target.value)} />

          {isRegisterMode && (
            <select onChange={e=>setNuevoRol(e.target.value)}>
              <option value="vendedor">Vendedor</option>
              <option value="admin">Administrador</option>
            </select>
          )}

          {isRegisterMode
            ? <button onClick={handleRegister}>Registrarse</button>
            : <button onClick={handleLogin}>Entrar</button>
          }

          <p onClick={()=>setIsRegisterMode(!isRegisterMode)} style={{cursor:'pointer'}}>
            {isRegisterMode ? 'Ya tengo cuenta' : 'Crear cuenta'}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="main-wrapper">

      <Navbar
        setView={setView}
        userRole={userRole}
        logout={() => setIsLoggedIn(false)}
      />

      <main className="content-area">
        {view === "dashboard" ? (
          <div className="dashboard-grid">
            <div className="card">
              <h3>⚠️ Bajo Stock</h3>
              <p>{stats.bajo_stock} productos</p>
            </div>
            <div className="card">
              <h3>📊 Estadísticas</h3>
              <p>Total: {stats.total_productos}</p>
              <p>Valor: ${stats.valor_inventario}</p>
            </div>
          </div>
        ) : (
          <div className="card">
            <button onClick={()=>setShowForm(!showForm)}>+ Agregar</button>

            {showForm && (
              <>
                <input placeholder="Nombre" onChange={e=>setNuevoProd({...nuevoProd, nombre:e.target.value})}/>
                <input placeholder="Stock" type="number" onChange={e=>setNuevoProd({...nuevoProd, stock:e.target.value})}/>
                <input placeholder="Precio" type="number" onChange={e=>setNuevoProd({...nuevoProd, precio_venta:e.target.value})}/>
                <button onClick={guardarProducto}>Guardar</button>
              </>
            )}


            <table>
              <tbody>
                {productos.map(p=>(
                  <tr key={p.id}>
                    <td>{p.nombre}</td>
                    <td>{p.stock}</td>
                    <td>${p.precio_venta}</td>
                    <td>
                      <button onClick={()=>prepararEdicion(p)}>✏️</button>
                      <button onClick={()=>eliminar(p.id)}>🗑️</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
